fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let n = nums.len();
    let mut prefix_mod = vec![0; n + 1];
    let mut mod_counts = std::collections::HashMap::new();
    mod_counts.insert(0, 1);

    let mut total_sum = 0;
    for i in 0..n {
        total_sum += nums[i];
        let mod = (total_sum % k + k) % k;
        prefix_mod[i + 1] = mod;
    }

    mod_counts = std::collections::HashMap::new();
    mod_counts.insert(0, 1);

    for i in 0..n {
        let mod = (prefix_mod[i + 1] + k) % k;
        *mod_counts.entry(mod).or_insert(0) += 1;
    }

    let mut min_sum = 0;
    for (&mod_val, count) in &mod_counts {
        if count > 0 {
            min_sum += mod_val * count;
        }
    }

    min_sum
}
